"""Unit tests for src/eval.py."""import torchimport torch.nn as nnfrom src.eval import evaluate_inductionclass TinyModel(nn.Module):    """Mock model for testing eval functions."""    def __init__(self, vocab_size=50257, block_size=256):        super().__init__()        self.config = type("Config", (), {            "vocab_size": vocab_size,            "block_size": block_size,        })()    def forward(self, x, y=None):        B, T = x.shape        logits = torch.randn(B, T, self.config.vocab_size)        return logits, torch.tensor(0.0)    def train(self, mode=True):        return self    def eval(self):        return selfdef test_evaluate_induction_returns_float():    """evaluate_induction should return a float."""    model = TinyModel()    device = torch.device("cpu")    score = evaluate_induction(model, device, seed=42, batch_size=4)    assert isinstance(score, float)def test_evaluate_induction_deterministic():    """Same seed should give same result."""    model = TinyModel()    device = torch.device("cpu")    s1 = evaluate_induction(model, device, seed=42, batch_size=4)    s2 = evaluate_induction(model, device, seed=42, batch_size=4)    assert s1 == s2